     4→
     5→import {
     6→  appendFileSync,
     7→  copyFileSync,
     8→  existsSync,
     9→  mkdirSync,
    10→  readFileSync,
    11→  writeFileSync,
    12→} from 'node:fs'
    13→import { dirname } from 'node:path'
    14→import type { StorageAdapter } from './adapter.js'
    15→
    16→export class LocalAdapter implements StorageAdapter {
    17→  async writeFile(path: string, content: string | Buffer): Promise<void> {
    18→    mkdirSync(dirname(path), { recursive: true })
    19→    writeFileSync(path, content, typeof content === 'string' ? 'utf-8' : undefined)
    20→  }
    21→
    22→  async readFile(path: string): Promise<string> {
    23→    return readFileSync(path, 'utf-8')
    24→  }
    25→
